typedef struct { int s, e; } Book;
static Book cal[1000]; static int cn;
bool myCalendarBook(int start, int end) {
    for (int i = 0; i < cn; i++)
        if (start < cal[i].e && end > cal[i].s) return false;
    cal[cn].s = start; cal[cn++].e = end;
    return true;
